import Box from '@mui/material/Box'
import SelfiePicker, {SelfieType} from '../SelfiePicker/selfie-picker';
import Button from '@mui/material/Button';
import { useState } from "react";
import { ColorPicker, ColorPickerButton } from '../Shared/Layout/ColorPicker/colorpicker';
import useMediaQuery from '@mui/material/useMediaQuery';
import { createTheme } from '@mui/material/styles';

const theme = createTheme({
    palette: {
      primary: {
        main: '#0077c2',
      },
    },
  });

const images = [
    "Lela",
    "EmoLela",
    "AnimuLela",
    "ShortHairLela",
    "BraidedLela",
    "VulcanLela",
    "StraightHairLela",
    "BracesLela",
    "LelaOfGreenGables",
    "WhatTheCat",
    "RinguLela",
    "DudeLela"
];

function Home() {


    const [imageString, setImageString] = useState<string>("Lela");
    const [displayedImageName, setDisplayedImageName] = useState<string>("Lela");
    const [drawerOpen, setDrawerOpen] = useState<boolean>(false)

     //Make the colorpicker btn responsive
     const isMobile: boolean = useMediaQuery(theme.breakpoints.down('sm'));

    const SelfieType: SelfieType = {
        randomImage: imageString
    }

    function randomizeImg() {
        const randomImage = images[Math.floor(images.length * Math.random())];
        setImageString(randomImage);
        setDisplayedImageName(randomImage);
    }

    //Regex expression to split the img-namestring at the uppercased letters
    const formattedImageName = imageString.replace(/([A-Z])/g, ' $1');

    const handleColorPickerOpen = () => {
        setDrawerOpen(true);
    };

    return (
        <>
            <Box
                display="flex"
                justifyContent="center"
                height="400px"
            >
                <SelfiePicker {...SelfieType} />
            </Box>
            <Box
            textAlign="center"
            marginTop="120px"
            marginBottom="10px"
            marginLeft="40px"
            marginRight="40px"
            style={{
                backgroundColor: 'rgba(0, 0, 0, 0.5)',
                borderRadius: '15px',
                padding: '2px',
    
                color: '#fff'
              }}
            >
             <h3>{formattedImageName}</h3>
      </Box>
      <Box display="flex" justifyContent="center">
        <Button variant="contained" onClick={() => randomizeImg()}>
          Change Me
        </Button>
        {isMobile ? (
                <div onClick={() => handleColorPickerOpen()}>
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24">
                        <path d="M12.5 5.5a7 7 0 1 1 0 14 7 7 0 0 1 0-14m0-2a9 9 0 1 0 0 18 9 9 0 0 0 0-18m0-1a10 10 0 1 1 0 20 10 10 0 0 1 0-20z"/>
                    </svg>
                </div>
            ) : (
                <ColorPickerButton onClick={() => handleColorPickerOpen()} isMobile={isMobile} />
            )}
        </Box>
        <ColorPicker drawerOpen={drawerOpen} setDrawerOpen={setDrawerOpen} />
    </>
  )
}

export default Home;
